import React from 'react';
import {
  BarChart, Bar, XAxis, YAxis, CartesianGrid,
  Tooltip, ResponsiveContainer, Cell, Legend,
} from 'recharts';

/* ─── Colour palette ─────────────────────────────────────────── */
const C = {
  registered: '#1e40af',   // deep blue
  executed:   '#f97316',   // orange
  loi:        '#eab308',   // amber
};

/* ─── Custom tooltip shown on hover ─────────────────────────────*/
const CustomTooltip = ({ active, payload, label }) => {
  if (!active || !payload?.length) return null;

  // Only show rows that have a real value
  const rows = payload.filter(p => p.value > 0);
  if (!rows.length) return null;

  const total = rows.reduce((s, p) => s + p.value, 0);

  return (
    <div style={{
      background: '#fff',
      border: '1px solid #e2e8f0',
      borderRadius: 8,
      padding: '10px 14px',
      boxShadow: '0 4px 12px rgba(0,0,0,.12)',
      fontSize: 12,
      minWidth: 150,
    }}>
      <p style={{ fontWeight: 700, color: '#0f172a', margin: '0 0 8px' }}>{label}</p>
      {rows.map((p, i) => (
        <div key={i} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 12, marginBottom: 4 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            <div style={{ width: 10, height: 10, borderRadius: 2, background: p.fill }} />
            <span style={{ color: '#475569' }}>{p.name}</span>
          </div>
          <span style={{ fontWeight: 600, color: '#0f172a' }}>{p.value} unit{p.value !== 1 ? 's' : ''}</span>
        </div>
      ))}
      {rows.length > 1 && (
        <div style={{
          marginTop: 6, paddingTop: 6,
          borderTop: '1px solid #f1f5f9',
          display: 'flex', justifyContent: 'space-between',
        }}>
          <span style={{ color: '#64748b', fontSize: 11 }}>Total</span>
          <span style={{ fontWeight: 700, color: '#0f172a', fontSize: 11 }}>{total} unit{total !== 1 ? 's' : ''}</span>
        </div>
      )}
    </div>
  );
};

/* ─── Component ──────────────────────────────────────────────── */
const LeasingActivity = ({
  chartData,
  newLeases      = 0,
  areaLeased     = 0,
  loading        = false,
  loiCount       = 0,
  executedCount  = 0,
  registeredCount = 0,
}) => {

  /* ── Determine if there's any data worth showing ── */
  const hasRealData =
    loiCount > 0 || executedCount > 0 || registeredCount > 0 ||
    (Array.isArray(chartData) && chartData.some(d =>
      d.loiUnits > 0 || d.executedUnits > 0 || d.registeredUnits > 0
    ));

  const hasVisibleBars =
    Array.isArray(chartData) &&
    chartData.some(d => d.loiUnits > 0 || d.executedUnits > 0 || d.registeredUnits > 0);

  /*
    Build the final display data:
    – If chartData already has visible bars  → use it directly (months already correct)
    – Else if we have counts but no bar data → single bar for current month
    – Else                                   → empty (no chart)
  */
  let displayData = [];

  if (hasVisibleBars) {
    // Use the passed chartData — only keep months that have at least 1 unit
    displayData = (chartData || []).filter(d =>
      d.loiUnits > 0 || d.executedUnits > 0 || d.registeredUnits > 0
    );
  } else if (loiCount + executedCount + registeredCount > 0) {
    // Fallback: single bar for the current month
    const now      = new Date();
    const monthKey = now.toLocaleDateString('en-US', { month: 'short', year: '2-digit' });
    displayData = [{
      month:           monthKey,
      loiUnits:        loiCount,
      executedUnits:   executedCount,
      registeredUnits: registeredCount,
    }];
  }

  /* ── Date range label ── */
  const dateRangeLabel = displayData.length > 0
    ? displayData.length === 1
      ? displayData[0].month
      : `${displayData[0].month} – ${displayData[displayData.length - 1].month}`
    : '';

  /* ── Adaptive chart width so bars don't get squashed ── */
  const MIN_BAR_WIDTH  = 60;   // pixels per month column
  const chartMinWidth  = Math.max(300, displayData.length * MIN_BAR_WIDTH);

  return (
    <div className="echo-card" style={{ border: 'none', height: '100%' }}>
      {/* Title */}
      <h3 className="echo-card-title" style={{ marginBottom: 2 }}>Leasing Activity</h3>
      <p className="echo-card-subtitle" style={{ marginBottom: 14 }}>
        {loading
          ? 'Loading…'
          : hasRealData
            ? `${dateRangeLabel} · ${Number(areaLeased).toLocaleString('en-IN')} sqft leased`
            : 'No leasing activity yet'}
      </p>

      {/* KPI counters */}
      <div className="echo-leasing-stats" style={{ marginBottom: 16 }}>
        {[
          { label: 'LOI',               value: loiCount        },
          { label: 'Leasing Executed',  value: executedCount   },
          { label: 'Registered',        value: registeredCount },
        ].map(({ label, value }) => (
          <div key={label} className="echo-leasing-stat">
            <p className="echo-leasing-stat-label">{label}</p>
            <p className="echo-leasing-stat-value">{loading ? '…' : value}</p>
          </div>
        ))}
      </div>

      {/* ── Chart ── */}
      {loading ? (
        <div style={{ textAlign: 'center', padding: 40, color: '#94a3b8', fontSize: 13 }}>
          Loading chart…
        </div>
      ) : displayData.length > 0 ? (
        <>
          {/* Scrollable wrapper — prevents overflow */}
          <div style={{ overflowX: 'auto', overflowY: 'hidden', width: '100%', WebkitOverflowScrolling: 'touch' }}>
            <div style={{ minWidth: chartMinWidth, height: 200 }}>
              <ResponsiveContainer width="100%" height="100%">
                <BarChart
                  data={displayData}
                  barCategoryGap="30%"
                  barGap={3}
                  margin={{ top: 6, right: 16, left: -10, bottom: 4 }}
                >
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />

                  <XAxis
                    dataKey="month"
                    tick={{ fontSize: 10, fill: '#64748b' }}
                    axisLine={false}
                    tickLine={false}
                  />

                  <YAxis
                    tick={{ fontSize: 10, fill: '#64748b' }}
                    axisLine={false}
                    tickLine={false}
                    allowDecimals={false}
                    width={28}
                  />

                  <Tooltip
                    content={<CustomTooltip />}
                    cursor={{ fill: 'rgba(100,116,139,0.06)' }}
                  />

                  {/* Stacked bars — bottom to top: registered → executed → LOI */}
                  <Bar
                    dataKey="registeredUnits"
                    name="Registered"
                    stackId="units"
                    fill={C.registered}
                  />
                  <Bar
                    dataKey="executedUnits"
                    name="Executed"
                    stackId="units"
                    fill={C.executed}
                  />
                  <Bar
                    dataKey="loiUnits"
                    name="LOI"
                    stackId="units"
                    fill={C.loi}
                    radius={[3, 3, 0, 0]}
                  />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>

          {/* Legend */}
          <div style={{ display: 'flex', gap: 16, marginTop: 10, justifyContent: 'center', flexWrap: 'wrap' }}>
            {[
              { color: C.registered, label: 'Registered' },
              { color: C.executed,   label: 'Executed'   },
              { color: C.loi,        label: 'LOI'        },
            ].map(({ color, label }) => (
              <div key={label} style={{ display: 'flex', alignItems: 'center', gap: 5 }}>
                <div style={{ width: 10, height: 10, borderRadius: 2, background: color }} />
                <span style={{ fontSize: 11, color: '#475569' }}>{label}</span>
              </div>
            ))}
          </div>
        </>
      ) : (
        <div style={{ textAlign: 'center', padding: '40px 16px', color: '#64748b' }}>
          <p style={{ margin: 0, fontSize: 14 }}>No leasing activity recorded yet</p>
          <p style={{ margin: '6px 0 0', fontSize: 12, color: '#94a3b8' }}>
            Add LOI, Agreement, or Registration dates to a lease to see activity here
          </p>
        </div>
      )}
    </div>
  );
};

export default LeasingActivity;
